let targetAudience = '시니어';
let maxTopics = 5;
let persistCollected = true;
try {
  const wh = $('Webhook 수집').all();
  if (wh.length) {
    const raw = wh[0].json;
    const b = raw.body ?? raw;
    const parsed = typeof b === 'string' ? JSON.parse(b) : b;
    if (parsed?.targetAudience) targetAudience = String(parsed.targetAudience);
    if (parsed?.maxTopics != null) maxTopics = Number(parsed.maxTopics);
    if (parsed?.persistCollected != null) persistCollected = Boolean(parsed.persistCollected);
  }
} catch {}
if (!Number.isFinite(maxTopics) || maxTopics < 1) maxTopics = 5;
return [{ json: { targetAudience, maxTopics, persistCollected, source: 'n8n' } }];

const params = $('기준 설정').first().json;
const feeds = [
  { name: '동아일보', url: 'https://rss.donga.com/total.xml' },
  { name: '경향신문', url: 'https://www.khan.co.kr/rss/rssdata/total_news.xml' },
  { name: '매일경제', url: 'https://www.mk.co.kr/rss/30000001/' },
  { name: '한국경제', url: 'https://www.hankyung.com/feed/economy' },
  { name: '조선일보 경제', url: 'https://www.chosun.com/arc/outboundfeeds/rss/category/economy/?outputType=xml' },
];
const keywords = ['연금','재테크','은퇴','노후','시니어','실버','건강','국민연금','전세','금리','복지','상속','부동산','투자','절약','노인','요양','의료','물가','경제'];

function decode(t) {
  return t.replace(/<!\[CDATA\[([\s\S]*?)\]\]>/gi,'$1').replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').trim();
}
function tag(block, name) {
  const m = block.match(new RegExp('<'+name+'[^>]*>([\\s\\S]*?)<\\/'+name+'>','i'));
  return m ? decode(m[1]).replace(/<[^>]+>/g,' ').trim() : '';
}
function parseXml(xml) {
  const out = [];
  const blocks = xml.match(/<item[\s\S]*?<\/item>/gi) || [];
  for (const b of blocks) {
    const title = tag(b,'title');
    const link = tag(b,'link') || tag(b,'guid');
    if (!title) continue;
    out.push({ title: title.slice(0,500), link: link.slice(0,2000), pubDate: tag(b,'pubDate'), description: tag(b,'description').slice(0,500) });
  }
  return out;
}
function score(title, desc) {
  const text = (title+' '+desc).toLowerCase();
  let s = 0;
  for (const kw of keywords) { if (text.includes(kw)) s += title.includes(kw) ? 12 : 4; }
  return s;
}
function idFor(link, title) {
  let h = 0; const s = (link || title);
  for (let i = 0; i < s.length; i++) h = ((h << 5) - h) + s.charCodeAt(i);
  return 'rss' + Math.abs(h).toString(16).padStart(28, '0').slice(0, 28);
}

const scored = []; let feedOk = 0;
for (const feed of feeds) {
  try {
    const res = await this.helpers.httpRequest({ method: 'GET', url: feed.url, headers: { 'User-Agent': 'ContentsDashboard-n8n/1.0' }, timeout: 12000 });
    const xml = typeof res === 'string' ? res : JSON.stringify(res);
    const items = parseXml(xml);
    if (!items.length) continue;
    feedOk++;
    for (const it of items) {
      const rel = score(it.title, it.description || '');
      if (rel <= 0) continue;
      scored.push({ id: idFor(it.link, it.title), title: it.title, link: it.link || null, source_feed: feed.name, summary: it.description || null, published_at: it.pubDate ? new Date(it.pubDate).toISOString() : null, relevance_score: rel, target_audience: params.targetAudience, source: params.source });
    }
  } catch (e) { /* next feed */ }
}

scored.sort((a,b) => b.relevance_score - a.relevance_score);
const top = scored.slice(0, params.maxTopics * 3);

if (!feedOk) return [{ json: { ok: false, skipSave: true, message: 'RSS 피드 수집 실패', topics: [] } }];
if (!top.length) return [{ json: { ok: true, skipSave: !params.persistCollected, message: '관련 기사 없음', topics: [], savedCount: 0 } }];
if (!params.persistCollected) return [{ json: { ok: true, skipSave: true, preview: true, message: `미리보기 ${top.length}개`, topics: top, savedCount: 0 } }];

return [{ json: { ok: true, skipSave: false, topics: top, savedCount: top.length, maxTopics: params.maxTopics, targetAudience: params.targetAudience, message: `수집 ${top.length}개 (Gemini 정제 대기)` } }];

const rss = $input.first().json;
const geminiKey = ($env.GEMINI_API_KEY || '').trim();

// 저장 스킵이거나 키 없으면 Gemini 건너뜀
if (rss.skipSave || !rss.topics?.length || !geminiKey) {
  return [{ json: { ...rss, geminiSkip: true, geminiReason: !geminiKey ? 'GEMINI_API_KEY 미설정' : '저장 스킵' } }];
}

const topicList = rss.topics.slice(0, 15).map((t, i) => `${i+1}. ${t.title}`).join('\n');
const prompt = `당신은 ${rss.targetAudience || '시니어'} 타겟 유튜브·블로그 콘텐츠 전문 기획자입니다.\n아래 뉴스 기사 제목 목록에서 실제로 관심 가질 주제 ${rss.maxTopics || 5}개를 선별해 주세요.\n\n조건:\n- 클릭하고 싶은 유튜브 영상 제목으로 재구성 (30자 이내)\n- 선별 이유를 한 줄로 설명\n- JSON 배열로만 응답 (앞뒤 다른 텍스트 없이)\n\n응답 형식:\n[\n  {"rank":1,"original":"원본제목","youtube_title":"유튜브 제목 제안","reason":"선별 이유"},\n  ...\n]\n\n뉴스 제목 목록:\n${topicList}`;

return [{ json: {
  ...rss,
  geminiSkip: false,
  geminiKey,
  geminiPrompt: prompt,
} }];

const prev = $('Gemini 프롬프트 준비').first().json;
const geminiRaw = $input.first().json;

let aiTopics = [];
try {
  const text = geminiRaw?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const jsonMatch = text.match(/\[[\s\S]*\]/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    aiTopics = Array.isArray(parsed) ? parsed : [];
  }
} catch(e) { /* Gemini 파싱 실패 → 원본 사용 */ }

const originalTopics = prev.topics || [];
const maxTopics = prev.maxTopics || 5;

let enriched;
if (aiTopics.length > 0) {
  const matched = new Set();
  enriched = aiTopics.map((ai, i) => {
    const idx = originalTopics.findIndex((t, j) => !matched.has(j) && (t.title.includes(ai.original?.slice(0,10)) || ai.original?.includes(t.title.slice(0,10))));
    const base = idx >= 0 ? originalTopics[idx] : (originalTopics[i] || originalTopics[0]);
    if (idx >= 0) matched.add(idx);
    return {
      ...base,
      title: ai.youtube_title || base.title,
      summary: ai.reason ? `[Gemini] ${ai.reason}` : base.summary,
      relevance_score: (base?.relevance_score || 0) + 50,
      ai_title: ai.youtube_title || null,
      ai_reason: ai.reason || null,
    };
  }).slice(0, maxTopics);
} else {
  enriched = originalTopics.slice(0, maxTopics);
}

const now = new Date().toISOString();
const rows = enriched.map(t => ({ ...t, collected_at: now, updated_at: now }));

return [{ json: {
  ok: true,
  skipSave: false,
  topics: rows,
  savedCount: rows.length,
  aiEnhanced: aiTopics.length > 0,
  aiProvider: aiTopics.length > 0 ? 'gemini' : null,
  message: `${rows.length}개 주제${aiTopics.length > 0 ? ' (Gemini 정제 완료)' : ' (키워드 필터)'}`,
} }];

const built = $input.first().json;
return [{ json: {
  ok: true,
  mode: 'n8n',
  savedCount: built.savedCount ?? (built.topics || []).length,
  aiEnhanced: built.aiEnhanced ?? false,
  aiProvider: built.aiProvider ?? null,
  topics: built.topics || [],
  message: built.message || 'RSS 주제 수집 완료',
  timestamp: new Date().toISOString(),
} }];

const j = $input.first().json;
return [{ json: {
  ok: j.ok !== false,
  mode: 'n8n',
  preview: j.preview === true,
  savedCount: 0,
  aiEnhanced: false,
  topics: j.topics || [],
  message: j.message || '저장 스킵',
  timestamp: new Date().toISOString(),
} }];
